var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CITIZEN_EXTRA_A_CHARADE","text":{"KOREA":"이게 사실이야? 시니어가 살해 당했다고?","JPN":"これ、本当？　シニアが殺されたの？","ENG":"Is it true? Was the Senior murdered?","TWN":"這是真的嗎？Senior被殺了？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CITIZEN_EXTRA_B_CHARADE","text":{"KOREA":"그럼 이제 우린 어떻게 되는 거지? 샤레이드를 통제할 사람이 없는 건가?","JPN":"じゃあ、これから私たちはどうなるの？　シャレードを統制する人がいないってこと？","ENG":"What's going to happen to us? Is there no one to watch over Charade?","TWN":"那我們該怎麼辦？是不是沒人管理查雷德？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_EXTRA_B_CHARADE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_EXTRA_A_CHARADE","text":{"KOREA":"루머 아닐까? 이 사진이 진짜 시니어라는 증거도 없잖아.","JPN":"デマじゃない？　この写真が本物のシニアって証拠もないし。","ENG":"Maybe it's fake. There's no proof that this is a picture of the real Senior.","TWN":"這只是一個傳言，沒有證據證明這真的是Senior。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_EXTRA_B_CHARADE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CITIZEN_EXTRA_B_CHARADE","text":{"KOREA":"그럼 관리국은 지금 뭐하는데? 이런 논란을 방치하고 있다는 건, 문제가 있다는 반증 아니겠어?","JPN":"じゃあ、管理局は今何してるんだよ。こんなウワサを放置してるってことは、問題があるっていう証拠じゃないのか？","ENG":"What's the Administration doing, then? They're not doing anything about this. Isn't that proof that there's a problem?","TWN":"那麼管理局現在在做什麼？他們對這麼大的爭議置之不理，不就表示問題確實存在嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CITIZEN_EXTRA_A_CHARADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CITIZEN_EXTRA_B_CHARADE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"메스헤르츠 채널에서 전해드리는 속보입니다.","JPN":"マスヘルツチャンネルからの速報です。","ENG":"Breaking news, here from the Masshertz channel.","TWN":"來自梅斯赫茲頻道的快報。"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"금일 갑작스러운 침식사태 발발로 인해 소란이 빚어지고 있는 가운데, SNS 등지에서는 또다른 소식으로 논란이 불거지고 있습니다.","JPN":"本日、侵食事態騒動が起きている中、SNSなどでは別の話題が広まっています。","ENG":"The abrupt Corruption disaster that occurred today has been causing chaos, while the citizens are in disarray from the news that has been spreading through social media.","TWN":"今天突然爆發的侵蝕事件讓市民一片譁然，而同時在社群網路上傳出的另一個消息引發了爭議。"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드 관리국의 시니어로 알려진 인물이 살해되었으며, 이 현장을 캡처한 다수의 사진들이 유포된 것인데요.","JPN":"シャレード管理局のシニアと思わしき人物が殺害され、その現場を撮影した写真が多数流布されました。","ENG":"A man, known as the Senior of Charade City Management, has been found murdered, and several pictures of the crime scene have been leaked.","TWN":"據悉，疑似查雷德管理局Senior的人物被殺害，現場的一些照片已經在社群網路上流傳開來。"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"해당 사진은 빠르게 삭제되었으나 그 진위 여부에 대해 관리국 관계자 측에선 아직 별다른 해명이 없는 것으로…","JPN":"この写真は直ちに削除されましたが、その真偽のほどについては管理局の関係者から、まだ弁明されていない模様です……","ENG":"The photos were quickly removed, but the Administration has made no particular statement about the authenticity of the photos...","TWN":"這些照片很快就被刪除，但管理局仍未對照片真實與否公開表態……"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"망할…!!","JPN":"クソッ……！！","ENG":"Damn it...!!","TWN":"該死……！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"벌써 언론사를 통해 일파만파로 퍼져나가고 있군. 이미 통제를 벗어났어.","JPN":"もうマスメディアを通じてあちこちに広まっているな。すでにコントロールできなくなっている。","ENG":"Word is spreading everywhere through the press. It's out of our control.","TWN":"已經透過媒體傳播開來，失去控制了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"밀실살인극…? 지금 관리국을 상대로 뭘 하자는 거야?!","JPN":"密室殺人劇……？　管理局を相手に何をしているんだ！？","ENG":"A murder mystery...? Do they think the Administration is a joke?!","TWN":"密室殺人……？是想對管理局做什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"진정하게. 어차피 평생 숨길 일도 아니었잖나.","JPN":"落ち着きたまえ。どうせずっと隠すつもりもなかったのだろう？","ENG":"Calm down. It was going to be public someday.","TWN":"冷靜點，這件事本來就不可能永遠隱瞞下去。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 가볍게 털어 넘길 문제가 아니란 거 당신도 알잖아!","JPN":"そうやって軽く済ませられる問題ではないということ、あなたも知っているじゃないか！","ENG":"You know this isn't a small issue!","TWN":"你也知道的，這事情沒那麼簡單！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리도시가 침식체들 공격을 받고 있는 상황에서 시니어가 살해당했단 사실이 퍼졌어! 심지어 그 적나라한 범행 사진이 인터넷에 뿌려지고 있다고!","JPN":"管理都市が侵食体から攻撃されている状況で、シニアが殺害されたという噂が広まった！　しかも、その赤裸々な犯行写真がネットで流布されているんだぞ！","ENG":"An Administration City is being attacked by C.O.s, and word is spreading about how the Senior was murdered! Not to mention how the gruesome photos of the crime scene are all over the internet!","TWN":"城市被侵蝕體襲擊的情況下，Senior被謀殺的消息也傳開了！甚至連犯罪現場的照片也在網路上傳開了！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"범인이 리하르트의 죽음을 공표했다는 건, 샤레이드가 혼란에 빠지길 원한단 뜻이지.","JPN":"犯人がリヒャルトの死を公表したということは、シャレードの混乱を臨んでいるのだろう。","ENG":"The culprit made Richard's death public. That means they want Charade to fall into chaos.","TWN":"兇手公開理查的死訊，就表示他想讓查雷德陷入混亂。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네마저 흥분하면 결국 그 자의 의도대로 흘러가는 꼴이 아니겠나?","JPN":"君がそうやって興奮しては、あの者の思う壺になるのではないか？","ENG":"You'd be falling into the culprit's trap if you lose your temper.","TWN":"如果連你也失去理智，不正中他的下懷了嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"당신 말이 맞아.","JPN":"あなたの言うとおりだ。","ENG":"You're right.","TWN":"你說的對。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트의 죽음이 범인의 최종 목적이었다면, 이런 식으로 불필요하게 이목을 끌 필요는 없겠지.","JPN":"リヒャルトの死が犯人の最終目的であったなら、こんなふうに民衆の目を引く必要はない。","ENG":"If Richard's death was the culprit's ultimate goal, they wouldn't have needed to draw all this unnecessary attention.","TWN":"如果理查的死是兇手的最終目的，就沒有必要以這種方式引起不必要的注意。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이젠 녀석의 진짜 목적을 알아낼 차례야.","JPN":"これからは奴の本当の目的を突き止める番だ。","ENG":"Now it's time to figure out what their true objective is.","TWN":"現在是時候弄清楚他真正的目的了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"유력한 용의자를 찾아야 할 이유가 늘었군.","JPN":"有力な容疑者を探す理由が増えたな。","ENG":"All the more reason to find the likely culprit.","TWN":"這就更需要找到最重要的嫌犯了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"마침 연락이 왔네.","JPN":"ちょうど今、連絡が来た。","ENG":"Oh, good timing. I got a call.","TWN":"正好有消息傳來。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"어떻게 됐지? 스완은 찾았나?","JPN":"どうなった？　スワンは見つかったか？","ENG":"What's going on? Did you find Swan?","TWN":"怎麼樣？找到史旺了嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"역시… 관리국이 보낸 요원이었군요.","JPN":"やはり……管理局のエージェントだったのですね。","ENG":"So he was an agent sent by the Administration... just as I thought.","TWN":"果然……是管理局派的人。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"QM_MARK_ANY_NOIMAGE","text":{"KOREA":"관리국 시니어 르네. 당신에게 인사드리는 건 이번이 처음이겠네요.","JPN":"管理局シニア、ルネ。あなた方にご挨拶するのはこれが初めてになりますね。","ENG":"Renée, Senior of the Administration. I guess this is the first time we're talking.","TWN":"管理局Senior芮妮。這是我第一次向你問好。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 왜 그 통신기를 가지고 있지? 스완?","JPN":"どうしてあなたが通信機を持っているんだ？　スワン。","ENG":"How come you have that comms device, Swan?","TWN":"你為什麼會有那個通訊器？史旺？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그런 뻔한 질문을 설명하려고 연락을 드린 건 아닙니다.","JPN":"そのような質問に答えるために連絡したのではありません。","ENG":"I didn't call you just to answer such an obvious question.","TWN":"我聯繫你並不是為了回答這麼簡單的問題。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"전 당신에게 도발이 아닌, 경고를 하고 싶은 거니까요.","JPN":"私はあなたに挑発ではなく、警告をしたいのです。","ENG":"I don't mean to provoke you. I mean to warn you.","TWN":"我想給你們一個警告，而不是挑釁。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 나한테 경고를 한다고?","JPN":"あなたが、私に？","ENG":"\\"You\\" want to warn \\"me?\\"","TWN":"警告我？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"시니어의 죽음은 경고일 뿐이에요.","JPN":"シニアの死はただの警告です。","ENG":"The Senior's death was merely a warning.","TWN":"Senior的死只是一個警告。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"더 이상 절 쫓으려 한다면 그땐 당신도 무사하지 못할 겁니다.","JPN":"これ以上私を追うつもりなら、その時はあなたも無事では済みませんよ。","ENG":"You'll meet a similar fate if you keep coming after me.","TWN":"如果你再追我，連你自己也會陷入危險。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"사진을 퍼트린 게 너였군.","JPN":"写真をばら撒いたのはあなただったのだな。","ENG":"So it was you who spread the photo.","TWN":"原來就是你散播照片的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"왜 이런 짓을 벌이는 거지? 지금껏 쌓아온 부와 명성을 전부 버릴 정도로 너에게 필요한 게 있나?","JPN":"なぜこんなことを？　今まで積み重ねてきた富と名声を捨てるほど、必要なものがあるのか？","ENG":"Why are you doing this? What's so important to you that you're willing to throw away all the wealth and fame you've achieved?","TWN":"你為什麼要這麼做？ 你是不是迫切需要什麼東西，以至於不惜拋棄一直以來累積的財富和名聲？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 알지 않나요? 샤레이드에서 부와 명성이란 건 쓰다 버릴 수단일 뿐이란 걸.","JPN":"あなたもわかっているのでは？　シャレードで富と名声というのは、利用して捨てる手段でしかないのです。","ENG":"I'm sure you're aware that wealth and fame are just a means to an end.","TWN":"你知道的，不是嗎？在查雷德，財富和名聲只不過是達到目的的手段。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 대가로 얻고 싶은 게 고작 샤레이드가 혼란에 빠지는 꼴은 아니겠지?","JPN":"その対価で得たいものが、たかがシャレードの混乱だと言うのではあるまいな？","ENG":"And I doubt you're using them just to bring chaos to Charade.","TWN":"以那麼多財富和名聲為代價得到的只是讓查雷德陷入混亂？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피로트 나무.","JPN":"セフィロト。","ENG":"The Tree of Sephiroth.","TWN":"生命樹。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"옆에서 듣고 계신 분도 있을 테니, 힌트는 그 정도면 충분하겠죠.","JPN":"隣で聞いている方もいらっしゃるでしょうから、ヒントはこれで十分でしょう。","ENG":"That should be enough of a clue, considering the presence of the person listening next to you.","TWN":"這個提示應該足夠了吧？相信你們旁邊也有人在聽。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"네가 그걸 어떻게…?","JPN":"どうしてあなたがそれを……？","ENG":"How did you...?","TWN":"你怎麼會知道？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"모든 건 저의 각본대로 움직일 뿐입니다, 르네.","JPN":"すべては私の脚本通りに動くのです、ルネ。","ENG":"Everything is according to my script, Renée.","TWN":"一切都在按照我的劇本進行，芮妮。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 각본의 수많은 엑스트라들 중 하나지만…","JPN":"あなたは脚本の中、数多くのエキストラの一人にすぎませんが……","ENG":"You are one of many background characters of the script, but...","TWN":"你是劇本中眾多的臨時演員之一，但……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 사람은 이 무대를 처음부터 끝까지 지켜보는 관중이 되어야 하거든요.","JPN":"あの人にはこの舞台を最後まで見届ける観客になってもらわないと困るのですよ。","ENG":"He has to be a part of the audience and watch this performance from start to finish.","TWN":"那個人要擔任的是從頭到尾觀賞這個舞台表演的觀眾。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 게 자기가 원하는대로 흘러갈 거라 생각하다니. 오만하군.","JPN":"すべてが自分の思い通りになると思うか。傲慢だな。","ENG":"Arrogant of you to think that everything would go according to your plan.","TWN":"你以為一切都會按你的想法發展，真是傲慢。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 그렇지 않나요?","JPN":"あなたもそうではありませんか？","ENG":"Aren't you the same?","TWN":"你不也是這樣嗎？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세상이 만든 법칙을 거스르고, 자신이 원하는 형태로 현실을 바꾸고 있는 걸요.","JPN":"世界が作った法則に逆らい、自身の望む形へと現実を変えているのですから。","ENG":"You're defying the rules made by this world and changing reality into the form you want it to be.","TWN":"你無視世界的法則，按照自己的喜好扭曲現實。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흠, 나에게 이 정도로 관심을 갖는 팬이 있을 줄은 몰랐는데.","JPN":"ほう、これほど私に興味がある熱心なファンがいるとは知らなかったな。","ENG":"Hmm. I didn't know I had a fan who was interested in me like this.","TWN":"嗯，沒想到你竟然還是我的狂熱粉絲呢"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"맞아요. 전 당신의 열렬한 관중이자 팬입니다.","JPN":"そうです。私はあなたの熱烈な観客であり、ファンなのです。","ENG":"Yes. I am your biggest fan and audience.","TWN":"沒錯，我是你最忠實的觀眾和粉絲。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서 언젠가 제 무대에 당신을 초청하고 싶었어요.","JPN":"いつかあなたを私の舞台に招待したかった。","ENG":"Which is why I was meaning to invite you to my performance one day.","TWN":"所以總有一天想把你邀請到我的舞台。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 마침내, 제가 준비한 각본을 실현할 기회가 온 셈이죠.","JPN":"そしてやっと今、私の準備した脚本を実現するチャンスが来たのです。","ENG":"And finally, I have the chance to carry out my script.","TWN":"而我終於迎來了實現自己寫的劇本的機會。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇게까지 해서 나에게 뭘 보여주고 싶은 거지?","JPN":"そこまでして私に見せたいものとは何かね？","ENG":"So, what are you trying to show me by going through all this?","TWN":"你費這麼大勁是想給我看什麼？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 불가능하다 여겨 포기했던 일을… 실현해 보일 겁니다.","JPN":"あなたが不可能だと思い、諦めたことを……私が実現させてみせます。","ENG":"I will accomplish... what you deemed impossible and gave up on.","TWN":"你將實現……你認為不可能實現的事情。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니 부디, 당신이 이 극의 종장에 무사히 다다를 수 있기를…","JPN":"だから、どうかあなたがこの物語の終章に無事たどり着けるよう……","ENG":"So I sincerely hope you reach the finale of this play...","TWN":"所以，希望你能平安活到這個劇本的大結局……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"<color=#ffd34c>팬으로서 응원할게요.</color>","JPN":"<color=#ffd34c>ファンとして応援します。</color>","ENG":"<color=#ffd34c>As a fan.</color>","TWN":"<color=#ffd34c>我會作為粉絲為你加油。</color>"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_LOBBY_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"쯧.","JPN":"チッ。","ENG":"Tsk.","TWN":"嘖。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"발신지 전파를 추적해봤지만 실패했어.","JPN":"発信地の電波を追跡してみたが、失敗した。","ENG":"I tried tracking the call, but I failed.","TWN":"我試圖追蹤訊號來源，但失敗了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"아무래도 침식파가 강한 지역에 있는 것 같아.","JPN":"どうやら侵食波が強い地域にいるようだ。","ENG":"I think she's in an area with strong Corruption rays.","TWN":"看來她在一個侵蝕波非常強烈的地區。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇다면 특정하긴 힘들겠군. 로터스에서 그런 침식지대는 흔하니까.","JPN":"だとしたら、特定することは難しいだろうな。ロータスにはそのような侵食地帯が多い。","ENG":"That would be difficult to locate, then. Such Corrupted areas are common in Lotus.","TWN":"那就很難找到她的位置了。像這樣的侵蝕地區在洛德斯很常見。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그런데, 세피로트 나무라는 게 뭐길래 스완은 당신이 알고 있을 거라 확신하는 거지?","JPN":"ところで、セフィロトとは何だ？　どうしてスワンはあなたがそれを知っていると確信しているんだ？","ENG":"But what's this Tree of Sephiroth that Swan is so sure that you know of?","TWN":"不過史旺提到的生命樹是什麼東西？她會什麼肯定你知道？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리국 데이터베이스에서도 그런 이름은 접한 적이 없어.","JPN":"管理局のデータベースでも、そんな名前は聞いたことがない。","ENG":"I've never heard of that name before. Not even from the Administration's database.","TWN":"我在管理局的資料庫中也從未見過這個字眼。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 아는 그게 맞다면…","JPN":"彼女の言うものが私の知っているアレだとしたら……","ENG":"If it's what I think it is...","TWN":"據我了解……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모든 소원을 이뤄주는 힘이라고 할 수 있지.","JPN":"すべての願いを叶えてくれる力だと言えよう。","ENG":"It's the power that can grant all wishes.","TWN":"那是一種可以實現任何願望的力量。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"허…….","JPN":"はっ……","ENG":"Whoa...","TWN":"哈……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그런 말장난 같은 얘기가 정말 가능하긴 한 거야?","JPN":"そんな言葉の綾みたいな話が、本当に存在するのか？","ENG":"Is that kind of fairy tale crap even possible?","TWN":"真的有如此荒謬的東西？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"말장난 같은 이야기이기에, 나 또한 취급하지 않던 정보라네.","JPN":"言葉の綾のような話だからこそ、私も扱っていなかった情報さ。","ENG":"I didn't concern myself with the information because I also thought it was a fairy tale.","TWN":"正是因為太過荒謬，我也沒有認真看待。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그런 지식을 관리국이 가지고 있다 한들 아무도 접근할 방법이 없을 테니까.","JPN":"そのような知識を管理局が持っていたとしても、誰も触れる方法がなかっただろうからな。","ENG":"Even if the Administration were to possess that kind of knowledge, no one would be able to access it.","TWN":"即使管理局掌握了這些知識，也沒有人知道該如何存取。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그 여자가 찾고 있는 게 원숭이손이든 요술램프든 상관없어.","JPN":"あの女が探しているのが、サルの手でも魔法のランプでも構わない。","ENG":"It doesn't matter whether she's looking for the monkey's paw or a magic lamp.","TWN":"不管她要找的是一隻猴掌還是一盞神燈都不重要。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리국 시니어에게 손을 댄 이상 죗값을 치르게 될 거야.","JPN":"管理局のシニアに手を出した以上、罪を償うことになるだろう。","ENG":"She'll pay for murdering an Administration Senior.","TWN":"她既然對管理局Senior下了手，就一定會付出代價的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"반드시 그렇게 만들겠어.","JPN":"必ず、そうさせてみせる。","ENG":"No matter what.","TWN":"我一定會這麼做。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…물론일세.","JPN":"……もちろんだ。","ENG":"...Of course.","TWN":"……當然。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"시니어님. 샤레이드를 습격한 침식체들의 이동경로 파악을 마쳤습니다.","JPN":"シニア。シャレードを襲撃した侵食体たちの移動経路を把握しました。","ENG":"Ma'am. We figured out where the C.O.s that invaded Charade are heading.","TWN":"Senior，我們已經掌握了襲擊查雷德侵蝕體的移動路線。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"말씀하신 것처럼 한 지점에 밀집하고 있어요. 바로 좌표를 공유해드리겠습니다.","JPN":"おっしゃっていたとおり、ある地点に集中しています。すぐに座標を共有します。","ENG":"As you said, they are gathering in one location. I'll share the coordinates right away.","TWN":"就像您說的，他們正在向一處聚集，我馬上把座標分享給您。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"고생했다. 확인해보지.","JPN":"ご苦労だったな。確認しよう。","ENG":"Good work. I'll check it now.","TWN":"辛苦了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"여긴…?","JPN":"ここは……？","ENG":"This is...?","TWN":"這裡是……？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"샤레이드의 외딴 교외지로군. 이곳에 뭔가 있나?","JPN":"シャレードの郊外地だな。ここに何かあるのか？","ENG":"It's an isolated area out in the suburbs of Charade. Is there anything there?","TWN":"查雷德的一個偏遠郊區，這裡有什麼東西嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"관리국에서 개발 중인 부지 중 하나인데.","JPN":"管理局が開発している敷地の一つだ。","ENG":"It's one of the sites that the Administration is developing.","TWN":"這是管理局正在開發的腹地之一。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"연구단지가 들어설 계획이었지만 아직 미완성이라 조난자용 쉼터 정도 밖에 없어.","JPN":"研究団地が建てられる予定だったが、まだ未完成で今は遭難者用の休憩所しかない。","ENG":"The plan was to establish a research complex, but it's still in the works. Currently, there's nothing but a shelter for survivors.","TWN":"這裡本應是一個研究園區，但現在還沒有完工，所以目前只有一個為遇難者準備的庇護所。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"이곳을 직접 관리하던 리하르트라면 몰라도, 나로선 그게 알고 있는 전부야.","JPN":"ここを直接管理していたリヒャルトならともかく、私が知っている情報はそのくらいだ。","ENG":"Richard might've known more since this city was under his jurisdiction, but that's all I know about the place.","TWN":"我只知道這麼多，曾親自管理這一地區的理查可能知道更多。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"직접 확인하지 않으면 침식체가 몰리는 이유도 알 수 없다는 뜻이군.","JPN":"直接確認してみない限り、侵食体が集まる理由もわからないということか。","ENG":"Which means, we won't know why the C.O.s are gathering there unless we check the area ourselves.","TWN":"這表示只有親自去確認才能弄清楚侵蝕體聚集的原因。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내가 가보겠네.","JPN":"私が行ってみよう。","ENG":"I'll go.","TWN":"我去吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"뭐?","JPN":"なんだと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"잊었어? 당신은 지금 관리국의 보호감찰 대상이야.","JPN":"忘れたのか？　あなたは今、管理局の保護観察の対象だ。","ENG":"You're under the protection and supervision of the Administration right now, or did you forget that?","TWN":"你忘了？你現在是管理局的監護對象。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자네도 알지 않나. 관리국에 명령을 내려 이 상황에 대처할 수 있는 건 자네 뿐이야.","JPN":"君も知っているだろう？　管理局に命令を出してこの状況に対処できるのは君だけだ。","ENG":"I'm sure you're well aware that you're the only one who can give orders to the Administration and manage this situation.","TWN":"你應該也知道，能夠向管理局下達命令應對這種情況的人只有你了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 이쪽은 날 믿고 맡겨줬으면 좋겠군.","JPN":"だから、ここは私を信じて任せてほしい。","ENG":"So, I'd like you to trust me with this task.","TWN":"所以我希望交給我處理。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"솔직히 말해, 당신을 믿고 보내는 게 옳은 선택일지 확신이 안 서.","JPN":"正直、あなたを信じて行かせることがいい選択なのか確信が持てない。","ENG":"Honestly, I'm not sure if it's the right choice to let you go.","TWN":"老實說，我不確定讓你去是不是正確的選擇。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"하지만 난 지금 샤레이드의 권한대행…","JPN":"だが、私は今シャレードの権限代行……","ENG":"But I'm the acting Senior of Charade right now...","TWN":"但我現在是查雷德的權限代理人……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"리하르트가 지금과 똑같은 상황에 처했다면, 당신을 믿는다는 판단을 내렸겠지.","JPN":"リヒャルトが今の私と同じ状況であったなら、あなたを信じると判断しただろう。","ENG":"And if Richard were here, he'd trust you.","TWN":"如果理查遇到相同的情況，他也一定會選擇信任你。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그러니 다녀와.","JPN":"だから、行って来い。","ENG":"So go.","TWN":"所以，你快去吧。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"고맙군. 실망시키지 않겠네.","JPN":"ありがとう。必ず期待に応えてみせよう。","ENG":"Thank you. I won't let you down.","TWN":"謝謝，我不會讓你失望的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 잘난 척 말해놓고 무슨 일 생기면 가만 안 둬.","JPN":"そう偉そうに話しておいて、何かあったらタダではおかないからな。","ENG":"Don't you dare get into trouble after acting all tough.","TWN":"要是出什麼意外，我絕不會原諒你。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"아, 그리고 날 대신해 도와줄 친구들에게 연락을 돌렸으니 곧 현장에 도착할 걸세.","JPN":"あ、そして私の代わりに手伝ってくれる友人に連絡をしておいた。もうすぐ現場に到着するだろう。","ENG":"Ah, and I've contacted some friends who will come to help in my place. They'll be arriving soon.","TWN":"對了，我已經聯絡了一些朋友，他們應該很快就會到現場幫助我。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그러니 도시 방비의 공백은 너무 걱정 말게나.","JPN":"だから、街の防備はあまり心配するな。","ENG":"So don't worry too much about the gap in the city's defenses.","TWN":"因此不必擔心城市防禦會有漏洞。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"흥, 회사가 묶인 마당에 당신이 뭘 할 수 있을진 모르겠지만…","JPN":"ふん、会社が縛られているくせにあなたに何ができるかはわからないが……","ENG":"Hmpf, I don't know what you're capable of when your company's tied up...","TWN":"哼，雖然不知道在公司被控制的情況下你還能做什麼……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GROUND_ADMIN_NULL_NULL","text":{"KOREA":"알아는 둘게.","JPN":"一応覚えておく。","ENG":"But I'll take note of that.","TWN":"總之我明白了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GROUND_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};